/// <summary>
/// Data provider for the @TaxTransactionInquiry:HeaderNote report.
/// Extends <c>SrsReportDataProviderBase</c> and populates the <c>ConDemoNoteReportAdvTmp</c> temporary table.
/// </summary>
[
    SRSReportParameterAttribute(classStr(ConDemoNoteReportAdvContract))
]
public class ConDemoNoteReportAdvDP extends SrsReportDataProviderBase
{
    ConDemoNoteReportAdvTmp conDemoNoteReportAdvTmp;

}

Method.Source:
/// <summary>
/// Returns the temporary table buffer used by the report dataset.
/// </summary>
/// <returns>The <c>ConDemoNoteReportAdvTmp</c> table buffer.</returns>
[SRSReportDataSetAttribute(tableStr(ConDemoNoteReportAdvTmp))]
public ConDemoNoteReportAdvTmp getConDemoNoteReportAdvTmp()
{
    select conDemoNoteReportAdvTmp;
    return conDemoNoteReportAdvTmp;
}

/// <summary>
/// Main data processing method. Populates the <c>ConDemoNoteReportAdvTmp</c> temporary table
/// with report data based on the contract parameters.
/// </summary>
public void processReport()
{
    ConDemoNoteReportAdvContract contract = this.parmDataContract() as ConDemoNoteReportAdvContract;
    str subjectFilter = contract.parmSubjectFilter();
    ConDemoNoteHeader noteHeader;

    if (!subjectFilter)
    {
        subjectFilter = '*';
    }

    insert_recordset conDemoNoteReportAdvTmp (NoteId, Subject)
        select NoteId, Subject from noteHeader
            where noteHeader.Subject like subjectFilter;
}
